CREATE TABLE IF NOT EXISTS sup_price_agreement (
 agreement_id bigint NOT NULL AUTO_INCREMENT,agreement_ref varchar(64) NOT NULL,contract_id bigint NOT NULL,quote_id bigint NOT NULL,supplier_id bigint NOT NULL,currency varchar(8) NOT NULL,effective_from date NOT NULL,effective_to date NOT NULL,agreement_status smallint NOT NULL COMMENT '1生效 2终止',source_contract_version int NOT NULL,created_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),updated_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),PRIMARY KEY(agreement_id),UNIQUE KEY uk_sup_agreement_ref(agreement_ref),UNIQUE KEY uk_sup_agreement_contract(contract_id),KEY idx_sup_agreement_lookup(supplier_id,agreement_status,effective_from,effective_to)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='合同生效价格协议读模型';
CREATE TABLE IF NOT EXISTS sup_price_agreement_line (
 agreement_line_id bigint NOT NULL AUTO_INCREMENT,agreement_id bigint NOT NULL,sku_code varchar(64) NOT NULL,unit_price decimal(18,6) NOT NULL,tax_rate decimal(5,2) NOT NULL,moq decimal(18,4) NOT NULL,delivery_days int NOT NULL,created_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),updated_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),PRIMARY KEY(agreement_line_id),UNIQUE KEY uk_sup_agreement_line(agreement_id,sku_code),KEY idx_sup_agreement_sku(sku_code)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='价格协议SKU行读模型';
